import subprocess
import os

def convertDocument(input_file, output_file, format_type):
    # Get the absolute path of input file
    input_path = os.path.abspath(input_file)
    
    # Get the absolute path of output file
    output_path = os.path.abspath(output_file)
    
    # Create the LibreOffice command
    cmd = [
        'libreoffice',
        '--headless',
        '--convert-to',
        format_type,
        '--outdir',
        os.path.dirname(output_path),
        input_path
    ]
    
    # Execute the command
    try:
        subprocess.run(cmd, check=True, capture_output=True)
        
        # If format_type is pdf, we need to rename the output file
        if format_type == 'pdf':
            # LibreOffice creates a file with same name but .pdf extension
            base_name = os.path.splitext(input_file)[0]
            temp_output = os.path.join(os.path.dirname(output_path), base_name + '.pdf')
            if os.path.exists(temp_output):
                os.rename(temp_output, output_path)
    except subprocess.CalledProcessError as e:
        raise Exception(f"Conversion failed: {e.stderr.decode('utf-8')}")